// allData: 在线版保留所有日期数据，按需加载
const allData = {};

// Cache
const loadedDates = {};

async function loadDateData(date) {
    if (loadedDates[date]) return loadedDates[date];
    // 所有日期都尝试加载（JSON文件不存在时优雅返回null）
    if (!_allDates.includes(date)) {
        console.warn('Date not available online:', date);
        return null;
    }
    try {
        const fn = 'd_' + date.replace(/-/g, '') + '.json';
        const resp = await fetch(fn);
        if (!resp.ok) throw new Error('HTTP ' + resp.status);
        const data = await resp.json();
        loadedDates[date] = data;
        allData[date] = data;
        return data;
    } catch(e) {
        console.error('Failed to load', date, e);
        return null;
    }
}

