// 默认日期（由Python脚本根据数据完整性计算得出）
        const defaultDate = '2026-07-02';
        let currentDate = '';
        let currentSort = { field: 'net_market_value', order: 'desc' };
        
        // 初始化日期选择器
        function initDateSelector() {
            const selector = document.getElementById('dateSelector');
            const dates = _allDates.slice().reverse();
            
            dates.forEach(date => {
                const option = document.createElement('option');
                option.value = date;
                option.textContent = date;
                selector.appendChild(option);
            });
            
            // 默认选择日期（优先使用Python计算的默认日期，否则使用最新日期）
            const initialDate = defaultDate && dates.includes(defaultDate) ? defaultDate : dates[0];
            if (dates.length > 0) {
                selector.value = initialDate;
                currentDate = initialDate;
                renderTable(initialDate);
            }
            
            // 更新数据时间信息
            updateDataTimeInfo(dates);
        }
        
        // 更新数据时间信息
        function updateDataTimeInfo(dates) {
            if (dates.length === 0) return;
            
            const latestDate = dates[0];
            const earliestDate = dates[dates.length - 1];
            
            // 更新最新数据时间
            const elLatest = document.getElementById('latestDataTime'); if (elLatest) elLatest.textContent = latestDate;
            
            // 更新数据范围
            const elRange = document.getElementById('dataRange'); if (elRange) elRange.textContent = `${earliestDate} 至 ${latestDate}`;
            
            // 检查缺失数据
            if (typeof checkMissingData === 'function') checkMissingData(dates);
            
            // 生成交易日历
            if (typeof generateTradingCalendar === 'function') generateTradingCalendar(dates);
        }
        
        // 检查缺失数据
        function checkMissingData(dates) {
            const missingInfo = document.getElementById('missingDataInfo');
            if (dates.length < 2) {
                missingInfo.style.display = 'none';
                return;
            }
            
            // 计算日期间隔
            const dateObjs = dates.map(d => new Date(d)).sort((a, b) => a - b);
            const oneDay = 24 * 60 * 60 * 1000;
            const gaps = [];
            
            for (let i = 1; i < dateObjs.length; i++) {
                const diffDays = Math.round((dateObjs[i] - dateObjs[i-1]) / oneDay);
                if (diffDays > 1) {
                    const startDate = dateObjs[i-1].toISOString().split('T')[0];
                    const endDate = dateObjs[i].toISOString().split('T')[0];
                    gaps.push(`${startDate} 至 ${endDate}`);
                }
            }
            
            if (gaps.length > 0) {
                missingInfo.innerHTML = `<strong>⚠️ 数据缺失：</strong>${gaps.join('、')}`;
                missingInfo.style.display = 'block';
            } else {
                missingInfo.style.display = 'none';
            }
        }
        
        // 生成交易日历
        function generateTradingCalendar(dates) {
            const calendarContainer = document.getElementById('tradingCalendar');
            if (dates.length === 0) return;
            
            const dateSet = new Set(dates);
            const latestDate = new Date(dates[0]);
            const year = latestDate.getFullYear();
            const month = latestDate.getMonth();
            
            // 获取月份第一天和最后一天
            const firstDay = new Date(year, month, 1);
            const lastDay = new Date(year, month + 1, 0);
            
            // 获取第一天是星期几（0=周日）
            const startWeekday = firstDay.getDay();
            
            let html = '<div class="calendar-grid">';
            
            // 星期标题
            const weekdays = ['日', '一', '二', '三', '四', '五', '六'];
            weekdays.forEach(day => {
                html += `<div class="calendar-weekday">${day}</div>`;
            });
            
            // 空白格子
            for (let i = 0; i < startWeekday; i++) {
                html += '<div class="calendar-day empty"></div>';
            }
            
            // 日期格子
            for (let day = 1; day <= lastDay.getDate(); day++) {
                const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                const hasData = dateSet.has(dateStr);
                const isToday = dateStr === dates[0];
                
                let className = 'calendar-day';
                if (hasData) className += ' has-data';
                if (isToday) className += ' today';
                
                html += `<div class="${className}">${day}</div>`;
            }
            
            html += '</div>';
            calendarContainer.innerHTML = html;
        }
        
        // 切换日期
        async function changeDate() {
            currentDate = document.getElementById('dateSelector').value;
            if (!allData[currentDate]) {
                showLoadingOverlay(true);
                const data = await loadDateData(currentDate);
                showLoadingOverlay(false);
                if (!data) {
                    alert('该日期数据不可用（仅保留最近7天数据）');
                    return;
                }
            }
            renderTable(currentDate);
        }
        
        // 排序表格
        function sortTable(field) {
            // 切换排序方向
            if (currentSort.field === field) {
                currentSort.order = currentSort.order === 'asc' ? 'desc' : 'asc';
            } else {
                currentSort.field = field;
                currentSort.order = 'desc'; // 默认降序
            }
            
            // 更新按钮状态
            const btn = document.getElementById('sortByMarketValue');
            if (field === 'net_market_value') {
                btn.classList.add('active');
                btn.textContent = currentSort.order === 'desc' ? '按净头寸市值排序 ↓' : '按净头寸市值排序 ↑';
            } else {
                btn.classList.remove('active');
                btn.textContent = '按净头寸市值排序';
            }
            
            // 更新表头样式
            document.querySelectorAll('th').forEach(th => {
                th.classList.remove('sorted-asc', 'sorted-desc');
            });
            
            renderTable(currentDate);
        }
        
        // 导出为Excel
        function exportToExcel() {
            const data = allData[currentDate];
            if (!data || data.length === 0) {
                alert('当前日期没有数据可导出');
                return;
            }
            
            // 构建Excel内容 (HTML表格格式)
            let html = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">';
            html += '<head><meta charset="UTF-8"><style>th{background-color:#4472C4;color:white;} td{border:1px solid #ddd;}</style></head><body>';
            html += '<table border="1">';
            
            // 表头
            html += '<tr>';
            html += '<th>品种</th>';
            html += '<th>多单总量</th>';
            html += '<th>空单总量</th>';
            html += '<th>净头寸</th>';
            html += '<th>净头寸市值</th>';
            html += '<th>多单人数</th>';
            html += '<th>空单人数</th>';
            html += '<th>多单利润</th>';
            html += '<th>空单利润</th>';
            html += '<th>多单占比</th>';
            html += '<th>空单占比</th>';
            html += '</tr>';
            
            // 数据行
            data.forEach(row => {
                html += '<tr>';
                html += `<td>${row.code}(${row.name})</td>`;
                html += `<td>${row.long_volume}</td>`;
                html += `<td>${row.short_volume}</td>`;
                html += `<td>${row.net_position > 0 ? '+' : ''}${row.net_position}</td>`;
                html += `<td>${row.net_market_value.toFixed(2)}</td>`;
                html += `<td>${row.long_accounts}</td>`;
                html += `<td>${row.short_accounts}</td>`;
                html += `<td>${row.long_profit > 0 ? '+' : ''}${row.long_profit.toFixed(2)}</td>`;
                html += `<td>${row.short_profit > 0 ? '+' : ''}${row.short_profit.toFixed(2)}</td>`;
                html += `<td>${row.long_ratio.toFixed(1)}%</td>`;
                html += `<td>${row.short_ratio.toFixed(1)}%</td>`;
                html += '</tr>';
            });
            
            html += '</table></body></html>';
            
            // 下载文件
            const blob = new Blob([html], { type: 'application/vnd.ms-excel' });
            const link = document.createElement('a');
            link.href = URL.createObjectURL(blob);
            link.download = `品种持仓表_${currentDate}.xls`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
        
        // 导出为CSV
        function exportToCSV() {
            const data = allData[currentDate];
            if (!data || data.length === 0) {
                alert('当前日期没有数据可导出');
                return;
            }
            
            // CSV表头
            let csv = '品种,多单总量,空单总量,净头寸,净头寸市值,多单人数,空单人数,多单利润,空单利润,多单占比,空单占比' + '\n';
            
            // CSV数据行
            data.forEach(row => {
                csv += `"${row.code}(${row.name})",`;
                csv += `${row.long_volume},`;
                csv += `${row.short_volume},`;
                csv += `${row.net_position},`;
                csv += `${row.net_market_value.toFixed(2)},`;
                csv += `${row.long_accounts},`;
                csv += `${row.short_accounts},`;
                csv += `${row.long_profit.toFixed(2)},`;
                csv += `${row.short_profit.toFixed(2)},`;
                csv += `${row.long_ratio.toFixed(1)}%,`;
                csv += `${row.short_ratio.toFixed(1)}%` + '\n';
            });
            
            // 添加UTF-8 BOM以支持中文
            const BOM = '﻿';
            const blob = new Blob([BOM + csv], { type: 'text/csv;charset=utf-8;' });
            const link = document.createElement('a');
            link.href = URL.createObjectURL(blob);
            link.download = `品种持仓表_${currentDate}.csv`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
        }
        
