        // 绘制净头寸市值曲线图
        function drawMarketValueChart(varietyCode) {
            const canvas = document.getElementById('marketValueChartCanvas');
            const ctx = canvas.getContext('2d');
            
            // 设置canvas尺寸
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            
            const width = canvas.width;
            const height = canvas.height;
            const padding = { top: 40, right: 40, bottom: 60, left: 80 };
            
            // 获取数据
            const series = timeSeries[varietyCode];
            if (!series || series.length === 0) return;
            
            const dates = series.map(s => s.date);
            const values = series.map(s => s.net_market_value);
            
            // 计算范围
            const minValue = Math.min(...values);
            const maxValue = Math.max(...values);
            const valueRange = maxValue - minValue || 1;
            
            // 清空画布
            ctx.clearRect(0, 0, width, height);
            
            // 绘制网格线
            ctx.strokeStyle = 'rgba(255,255,255,0.1)';
            ctx.lineWidth = 1;
            
            // 横向网格线
            for (let i = 0; i <= 5; i++) {
                const y = padding.top + (height - padding.top - padding.bottom) * i / 5;
                ctx.beginPath();
                ctx.moveTo(padding.left, y);
                ctx.lineTo(width - padding.right, y);
                ctx.stroke();
            }
            
            // 绘制零线
            const zeroY = padding.top + (height - padding.top - padding.bottom) * (maxValue / valueRange);
            ctx.strokeStyle = 'rgba(255,255,255,0.3)';
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(padding.left, zeroY);
            ctx.lineTo(width - padding.right, zeroY);
            ctx.stroke();
            ctx.setLineDash([]);
            
            // 绘制曲线
            const chartWidth = width - padding.left - padding.right;
            const chartHeight = height - padding.top - padding.bottom;
            
            ctx.strokeStyle = '#00d4ff';
            ctx.lineWidth = 2;
            ctx.beginPath();
            
            values.forEach((value, index) => {
                const x = padding.left + (index / (values.length - 1)) * chartWidth;
                const y = padding.top + ((maxValue - value) / valueRange) * chartHeight;
                
                if (index === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }
            });
            
            ctx.stroke();
            
            // 绘制数据点
            values.forEach((value, index) => {
                const x = padding.left + (index / (values.length - 1)) * chartWidth;
                const y = padding.top + ((maxValue - value) / valueRange) * chartHeight;
                
                ctx.fillStyle = value >= 0 ? '#ff6b6b' : '#51cf66';
                ctx.beginPath();
                ctx.arc(x, y, 4, 0, Math.PI * 2);
                ctx.fill();
            });
            
            // 绘制X轴标签（日期）
            ctx.fillStyle = '#888';
            ctx.font = '12px sans-serif';
            ctx.textAlign = 'center';
            
            dates.forEach((date, index) => {
                const x = padding.left + (index / (dates.length - 1)) * chartWidth;
                ctx.fillText(date.slice(5), x, height - padding.bottom + 20);
            });
            
            // 绘制Y轴标签（数值）
            ctx.textAlign = 'right';
            for (let i = 0; i <= 5; i++) {
                const value = maxValue - (valueRange * i / 5);
                const y = padding.top + (chartHeight * i / 5);
                ctx.fillText((value / 10000).toFixed(1) + '万', padding.left - 10, y + 4);
            }
            
            // 绘制标题
            ctx.fillStyle = '#00d4ff';
            ctx.font = 'bold 14px sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('净头寸市值（万元）', padding.left / 2, padding.top - 10);
        }
        
