        // 渲染表格
        function renderTable(date) {
            let data = allData[date];
            if (!data) return;
            
            document.getElementById('dateLabel').textContent = '数据日期: ' + date;
            
            // 排序数据
            data = [...data]; // 复制数组
            data.sort((a, b) => {
                let valA = a[currentSort.field];
                let valB = b[currentSort.field];
                
                // 对于市值，按绝对值排序
                if (currentSort.field === 'net_market_value') {
                    valA = Math.abs(valA);
                    valB = Math.abs(valB);
                }
                
                if (currentSort.order === 'asc') {
                    return valA - valB;
                } else {
                    return valB - valA;
                }
            });
            
            // 更新统计
            const bullish = data.filter(item => item.net_position > 0).length;
            const bearish = data.filter(item => item.net_position < 0).length;
            document.getElementById('totalVarieties').textContent = data.length;
            document.getElementById('bullishVarieties').textContent = bullish;
            document.getElementById('bearishVarieties').textContent = bearish;
            
            // 生成表格行
            let rowsHtml = '';
            data.forEach((item, index) => {
                const netClass = item.net_position > 0 ? 'positive' : 'negative';
                const netMvClass = item.net_market_value > 0 ? 'positive' : 'negative';
                const longProfitClass = item.long_profit > 0 ? 'positive' : 'negative';
                const shortProfitClass = item.short_profit > 0 ? 'positive' : 'negative';
                const highlightClass = index < 5 ? 'highlight' : ''; // 前5行高亮
                
                rowsHtml += `
                    <tr class="${highlightClass}">
                        <td class="variety-code">${item.code}</td>
                        <td class="variety-name clickable" onclick="showVarietyDetail('${item.code}', '${item.name}')">${item.name}</td>
                        <td class="positive">${item.long_volume.toLocaleString()}</td>
                        <td class="negative">${item.short_volume.toLocaleString()}</td>
                        <td class="${netClass} clickable" onclick="showPositionChart('${item.code}', '${item.name}')">${item.net_position.toLocaleString()}</td>
                        <td class="${netMvClass} clickable font-bold" onclick="showMarketValueChart('${item.code}', '${item.name}')">${item.net_market_value.toLocaleString()}</td>
                        <td class="clickable" onclick="showLongAccountsModal('${item.code}', '${item.name}')">${item.long_accounts}</td>
                        <td class="clickable" onclick="showShortAccountsModal('${item.code}', '${item.name}')">${item.short_accounts}</td>
                        <td class="${longProfitClass}">${item.long_profit}</td>
                        <td class="${shortProfitClass}">${item.short_profit}</td>
                        <td class="positive">${item.long_ratio}%</td>
                        <td class="negative">${item.short_ratio}%</td>
                    </tr>
                `;
            });
            
            document.getElementById('tableBody').innerHTML = rowsHtml;
        }
        
        // 显示品种详情页
        function showVarietyDetail(varietyCode, varietyName) {
            const modal = document.getElementById('varietyDetailModal');
            const title = document.getElementById('varietyDetailTitle');
            title.textContent = varietyName + '(' + varietyCode + ') - 品种详情分析';
            modal.style.display = 'block';
            
            // 获取当前日期的品种数据
            let varietyData = null;
            if (allData[currentDate]) {
                varietyData = allData[currentDate].find(item => item.code === varietyCode);
            }
            
            // 获取时间序列数据
            const series = timeSeries[varietyCode] || [];
            
            // 更新概览统计
            if (varietyData) {
                document.getElementById('detailLongVolume').textContent = varietyData.long_volume.toLocaleString();
                document.getElementById('detailShortVolume').textContent = varietyData.short_volume.toLocaleString();
                document.getElementById('detailNetPosition').textContent = varietyData.net_position.toLocaleString();
                document.getElementById('detailNetMarketValue').textContent = varietyData.net_market_value.toLocaleString();
                document.getElementById('detailLongAccounts').textContent = varietyData.long_accounts;
                document.getElementById('detailShortAccounts').textContent = varietyData.short_accounts;
                document.getElementById('detailLongProfit').textContent = (varietyData.long_profit >= 0 ? '+' : '') + varietyData.long_profit;
                document.getElementById('detailShortProfit').textContent = (varietyData.short_profit >= 0 ? '+' : '') + varietyData.short_profit;
                document.getElementById('detailLongRatio').textContent = varietyData.long_ratio + '%';
                document.getElementById('detailShortRatio').textContent = varietyData.short_ratio + '%';
                
                // 设置颜色
                document.getElementById('detailNetPosition').className = varietyData.net_position > 0 ? 'stat-value positive' : 'stat-value negative';
                document.getElementById('detailNetMarketValue').className = 'stat-value ' + (varietyData.net_market_value > 0 ? 'positive' : 'negative');
                document.getElementById('detailLongProfit').className = 'stat-value ' + (varietyData.long_profit > 0 ? 'positive' : 'negative');
                document.getElementById('detailShortProfit').className = 'stat-value ' + (varietyData.short_profit > 0 ? 'positive' : 'negative');
            }
            
            // 绘制多空对比图
            drawLongShortCompareChart(varietyData);
            
            // 绘制利润分布图
            drawProfitDistributionChart(varietyData);
            
            // 绘制双曲线图（净头寸市值 + 净头寸手数）
            drawVarietyDetailChart(varietyCode, series);
            
            // 更新历史数据表格
            updateVarietyHistoryTable(varietyCode, series);
        }
        
        // 绘制多空对比柱状图
        function drawLongShortCompareChart(varietyData) {
            const canvas = document.getElementById('longShortCompareChart');
            const ctx = canvas.getContext('2d');
            
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            
            const width = canvas.width;
            const height = canvas.height;
            const padding = { top: 30, right: 20, bottom: 50, left: 60 };
            
            ctx.clearRect(0, 0, width, height);
            
            if (!varietyData) return;
            
            const chartWidth = width - padding.left - padding.right;
            const chartHeight = height - padding.top - padding.bottom;
            
            // 数据
            const longVolume = varietyData.long_volume;
            const shortVolume = varietyData.short_volume;
            const longAccounts = varietyData.long_accounts;
            const shortAccounts = varietyData.short_accounts;
            
            const maxVolume = Math.max(longVolume, shortVolume);
            const maxAccounts = Math.max(longAccounts, shortAccounts);
            
            // 绘制网格线
            ctx.strokeStyle = 'rgba(255,255,255,0.1)';
            ctx.lineWidth = 1;
            for (let i = 0; i <= 4; i++) {
                const y = padding.top + chartHeight * i / 4;
                ctx.beginPath();
                ctx.moveTo(padding.left, y);
                ctx.lineTo(width - padding.right, y);
                ctx.stroke();
            }
            
            // 绘制手数对比柱状图
            const barWidth = chartWidth / 6;
            const scale = chartHeight / (maxVolume * 1.2);
            
            // 多单手数柱
            const longBarHeight = longVolume * scale;
            ctx.fillStyle = 'rgba(255,107,107,0.8)';
            ctx.fillRect(padding.left + barWidth, padding.top + chartHeight - longBarHeight, barWidth, longBarHeight);
            
            // 空单手数柱
            const shortBarHeight = shortVolume * scale;
            ctx.fillStyle = 'rgba(81,207,102,0.8)';
            ctx.fillRect(padding.left + barWidth * 3, padding.top + chartHeight - shortBarHeight, barWidth, shortBarHeight);
            
            // 绘制数值标签
            ctx.fillStyle = '#fff';
            ctx.font = '12px sans-serif';
            ctx.textAlign = 'center';
            
            // 手数标签
            ctx.fillText(longVolume.toLocaleString(), padding.left + barWidth * 1.5, padding.top + chartHeight - longBarHeight - 5);
            ctx.fillText(shortVolume.toLocaleString(), padding.left + barWidth * 3.5, padding.top + chartHeight - shortBarHeight - 5);
            
            // X轴标签
            ctx.fillStyle = '#888';
            ctx.fillText('多单手数', padding.left + barWidth * 1.5, height - padding.bottom + 20);
            ctx.fillText('空单手数', padding.left + barWidth * 3.5, height - padding.bottom + 20);
            
            // 绘制人数对比（右侧小柱状图）
            const accountScale = chartHeight / (maxAccounts * 1.2);
            const smallBarWidth = barWidth * 0.6;
            
            // 多单人数柱
            const longAccHeight = longAccounts * accountScale;
            ctx.fillStyle = 'rgba(255,107,107,0.5)';
            ctx.fillRect(padding.left + barWidth * 1.2, padding.top + chartHeight - longAccHeight, smallBarWidth, longAccHeight);
            
            // 空单人数柱
            const shortAccHeight = shortAccounts * accountScale;
            ctx.fillStyle = 'rgba(81,207,102,0.5)';
            ctx.fillRect(padding.left + barWidth * 3.2, padding.top + chartHeight - shortAccHeight, smallBarWidth, shortAccHeight);
            
            // Y轴标签
            ctx.fillStyle = '#888';
            ctx.font = '10px sans-serif';
            ctx.textAlign = 'right';
            for (let i = 0; i <= 4; i++) {
                const value = Math.round(maxVolume * (4 - i) / 4);
                ctx.fillText(value.toLocaleString(), padding.left - 5, padding.top + chartHeight * i / 4 + 3);
            }
        }
        
        // 绘制利润分布图
        function drawProfitDistributionChart(varietyData) {
            const canvas = document.getElementById('profitDistributionChart');
            const ctx = canvas.getContext('2d');
            
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            
            const width = canvas.width;
            const height = canvas.height;
            const padding = { top: 30, right: 20, bottom: 50, left: 60 };
            
            ctx.clearRect(0, 0, width, height);
            
            if (!varietyData) return;
            
            const chartWidth = width - padding.left - padding.right;
            const chartHeight = height - padding.top - padding.bottom;
            
            const longProfit = varietyData.long_profit;
            const shortProfit = varietyData.short_profit;
            
            // 计算范围
            const maxProfit = Math.max(Math.abs(longProfit), Math.abs(shortProfit));
            const scale = chartHeight / (maxProfit * 1.2 || 1);
            
            // 绘制零线
            const zeroY = padding.top + chartHeight / 2;
            ctx.strokeStyle = 'rgba(255,255,255,0.3)';
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(padding.left, zeroY);
            ctx.lineTo(width - padding.right, zeroY);
            ctx.stroke();
            ctx.setLineDash([]);
            
            // 绘制柱状图
            const barWidth = chartWidth / 5;
            
            // 多单利润柱
            const longBarHeight = Math.abs(longProfit) * scale;
            const longBarY = longProfit >= 0 ? zeroY - longBarHeight : zeroY;
            ctx.fillStyle = longProfit >= 0 ? 'rgba(255,107,107,0.8)' : 'rgba(81,207,102,0.8)';
            ctx.fillRect(padding.left + barWidth, longBarY, barWidth, longBarHeight);
            
            // 空单利润柱
            const shortBarHeight = Math.abs(shortProfit) * scale;
            const shortBarY = shortProfit >= 0 ? zeroY - shortBarHeight : zeroY;
            ctx.fillStyle = shortProfit >= 0 ? 'rgba(255,107,107,0.8)' : 'rgba(81,207,102,0.8)';
            ctx.fillRect(padding.left + barWidth * 3, shortBarY, barWidth, shortBarHeight);
            
            // 绘制数值标签
            ctx.fillStyle = '#fff';
            ctx.font = '12px sans-serif';
            ctx.textAlign = 'center';
            
            const longLabelY = longProfit >= 0 ? longBarY - 5 : longBarY + longBarHeight + 15;
            const shortLabelY = shortProfit >= 0 ? shortBarY - 5 : shortBarY + shortBarHeight + 15;
            
            ctx.fillText((longProfit >= 0 ? '+' : '') + longProfit, padding.left + barWidth * 1.5, longLabelY);
            ctx.fillText((shortProfit >= 0 ? '+' : '') + shortProfit, padding.left + barWidth * 3.5, shortLabelY);
            
            // X轴标签
            ctx.fillStyle = '#888';
            ctx.fillText('多单利润', padding.left + barWidth * 1.5, height - padding.bottom + 20);
            ctx.fillText('空单利润', padding.left + barWidth * 3.5, height - padding.bottom + 20);
            
            // Y轴标签
            ctx.fillStyle = '#888';
            ctx.font = '10px sans-serif';
            ctx.textAlign = 'right';
            for (let i = 0; i <= 4; i++) {
                const value = maxProfit * (2 - i) / 2;
                ctx.fillText(value.toFixed(0), padding.left - 5, padding.top + chartHeight * i / 4 + 3);
            }
        }
        
        // 显示市场分析弹窗
        function showMarketAnalysis() {
            const modal = document.getElementById('marketAnalysisModal');
            modal.style.display = 'block';
            
            // 生成热力图
            generateHeatmap();
        }
        
        // 关闭市场分析弹窗
        function closeMarketAnalysisModal() {
            document.getElementById('marketAnalysisModal').style.display = 'none';
        }
        
        // 生成热力图
        function generateHeatmap() {
            const container = document.getElementById('heatmapContainer');
            const data = allData[currentDate];
            
            if (!data || data.length === 0) {
                container.innerHTML = '<div style="color:#888;text-align:center;padding:40px;">暂无数据</div>';
                return;
            }
            
            // 按净头寸市值绝对值排序
            const sortedData = [...data].sort((a, b) => Math.abs(b.net_market_value) - Math.abs(a.net_market_value));
            
            // 计算最大值用于颜色映射
            const maxValue = Math.max(...sortedData.map(d => Math.abs(d.net_market_value)));
            
            let html = '';
            sortedData.forEach(item => {
                const intensity = Math.abs(item.net_market_value) / maxValue;
                const isLong = item.net_market_value > 0;
                
                // 颜色：多头用红色系，空头用绿色系
                const r = isLong ? Math.round(255 * (0.3 + intensity * 0.7)) : Math.round(81 * (0.3 + intensity * 0.7));
                const g = isLong ? Math.round(107 * (0.3 + intensity * 0.7)) : Math.round(207 * (0.3 + intensity * 0.7));
                const b = isLong ? Math.round(107 * (0.3 + intensity * 0.7)) : Math.round(102 * (0.3 + intensity * 0.7));
                
                html += `
                    <div class="heatmap-item" style="background: rgba(${r},${g},${b},0.6);" onclick="showVarietyDetail('${item.code}', '${item.name}'); closeMarketAnalysisModal();">
                        <div class="variety-code">${item.code}</div>
                        <div class="variety-value">${item.net_market_value}</div>
                    </div>
                `;
            });
            
            container.innerHTML = html;
        }
        
        // 绘制品种详情双曲线图
        function drawVarietyDetailChart(varietyCode, series) {
            const canvas = document.getElementById('varietyDetailChart');
            const ctx = canvas.getContext('2d');
            
            // 设置canvas尺寸
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
            
            const width = canvas.width;
            const height = canvas.height;
            const padding = { top: 40, right: 60, bottom: 60, left: 80 };
            
            if (!series || series.length === 0) {
                ctx.clearRect(0, 0, width, height);
                ctx.fillStyle = '#888';
                ctx.font = '14px sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText('暂无历史数据', width / 2, height / 2);
                return;
            }
            
            const dates = series.map(s => s.date);
            const marketValues = series.map(s => s.net_market_value);
            const positions = series.map(s => s.net_position);
            
            // 计算两个Y轴的范围
            const minMv = Math.min(...marketValues);
            const maxMv = Math.max(...marketValues);
            const mvRange = maxMv - minMv || 1;
            
            const minPos = Math.min(...positions);
            const maxPos = Math.max(...positions);
            const posRange = maxPos - minPos || 1;
            
            // 清空画布
            ctx.clearRect(0, 0, width, height);
            
            const chartWidth = width - padding.left - padding.right;
            const chartHeight = height - padding.top - padding.bottom;
            
            // 绘制网格线
            ctx.strokeStyle = 'rgba(255,255,255,0.1)';
            ctx.lineWidth = 1;
            
            for (let i = 0; i <= 5; i++) {
                const y = padding.top + chartHeight * i / 5;
                ctx.beginPath();
                ctx.moveTo(padding.left, y);
                ctx.lineTo(width - padding.right, y);
                ctx.stroke();
            }
            
            // 绘制零线
            const zeroYMv = padding.top + chartHeight * (maxMv / mvRange);
            
            ctx.strokeStyle = 'rgba(255,255,255,0.3)';
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(padding.left, zeroYMv);
            ctx.lineTo(width - padding.right, zeroYMv);
            ctx.stroke();
            ctx.setLineDash([]);
            
            // 绘制净头寸市值曲线（左轴）
            ctx.strokeStyle = '#00d4ff';
            ctx.lineWidth = 2;
            ctx.beginPath();
            
            marketValues.forEach((value, index) => {
                const x = padding.left + (index / (marketValues.length - 1)) * chartWidth;
                const y = padding.top + ((maxMv - value) / mvRange) * chartHeight;
                
                if (index === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }
            });
            ctx.stroke();
            
            // 绘制净头寸市值数据点
            marketValues.forEach((value, index) => {
                const x = padding.left + (index / (marketValues.length - 1)) * chartWidth;
                const y = padding.top + ((maxMv - value) / mvRange) * chartHeight;
                
                ctx.fillStyle = value >= 0 ? '#ff6b6b' : '#51cf66';
                ctx.beginPath();
                ctx.arc(x, y, 4, 0, Math.PI * 2);
                ctx.fill();
            });
            
            // 绘制净头寸手数曲线（右轴）
            ctx.strokeStyle = '#ffd43b';
            ctx.lineWidth = 2;
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            
            positions.forEach((value, index) => {
                const x = padding.left + (index / (positions.length - 1)) * chartWidth;
                const y = padding.top + ((maxPos - value) / posRange) * chartHeight;
                
                if (index === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }
            });
            ctx.stroke();
            ctx.setLineDash([]);
            
            // 绘制净头寸手数数据点
            positions.forEach((value, index) => {
                const x = padding.left + (index / (positions.length - 1)) * chartWidth;
                const y = padding.top + ((maxPos - value) / posRange) * chartHeight;
                
                ctx.fillStyle = value >= 0 ? '#ff6b6b' : '#51cf66';
                ctx.beginPath();
                ctx.arc(x, y, 3, 0, Math.PI * 2);
                ctx.fill();
            });
            
            // 绘制X轴标签
            ctx.fillStyle = '#888';
            ctx.font = '11px sans-serif';
            ctx.textAlign = 'center';
            
            dates.forEach((date, index) => {
                const x = padding.left + (index / (dates.length - 1)) * chartWidth;
                ctx.fillText(date.slice(5), x, height - padding.bottom + 20);
            });
            
            // 绘制左Y轴标签（市值）
            ctx.textAlign = 'right';
            ctx.fillStyle = '#00d4ff';
            for (let i = 0; i <= 5; i++) {
                const value = maxMv - (mvRange * i / 5);
                const y = padding.top + (chartHeight * i / 5);
                ctx.fillText((value / 10000).toFixed(1) + '万', padding.left - 10, y + 4);
            }
            
            // 绘制右Y轴标签（手数）
            ctx.textAlign = 'left';
            ctx.fillStyle = '#ffd43b';
            for (let i = 0; i <= 5; i++) {
                const value = maxPos - (posRange * i / 5);
                const y = padding.top + (chartHeight * i / 5);
                ctx.fillText(value.toLocaleString(), width - padding.right + 10, y + 4);
            }
            
            // 绘制图例
            ctx.font = '12px sans-serif';
            ctx.textAlign = 'left';
            
            // 市值图例
            ctx.fillStyle = '#00d4ff';
            ctx.fillRect(padding.left, 15, 15, 3);
            ctx.fillText('净头寸市值', padding.left + 20, 20);
            
            // 手数图例
            ctx.fillStyle = '#ffd43b';
            ctx.setLineDash([5, 5]);
            ctx.beginPath();
            ctx.moveTo(padding.left + 100, 16);
            ctx.lineTo(padding.left + 115, 16);
            ctx.stroke();
            ctx.setLineDash([]);
            ctx.fillText('净头寸手数', padding.left + 120, 20);
        }
        
        // 更新品种历史数据表格
        function updateVarietyHistoryTable(varietyCode, series) {
            const tbody = document.getElementById('varietyHistoryTableBody');
            let html = '';
            
            if (!series || series.length === 0) {
                html = '<tr><td colspan="5" style="text-align:center;color:#888;padding:20px;">暂无历史数据</td></tr>';
            } else {
                // 倒序显示（最新的在前面）
                const reversedSeries = [...series].reverse();
                
                reversedSeries.forEach((item, index) => {
                    const netClass = item.net_position > 0 ? 'positive' : 'negative';
                    const mvClass = item.net_market_value > 0 ? 'positive' : 'negative';
                    
                    html += `
                        <tr>
                            <td>${item.date}</td>
                            <td>${item.long_volume.toLocaleString()}</td>
                            <td>${item.short_volume.toLocaleString()}</td>
                            <td class="${netClass}">${item.net_position.toLocaleString()}</td>
                            <td class="${mvClass}">${item.net_market_value.toLocaleString()}</td>
                        </tr>
                    `;
                });
            }
            
            tbody.innerHTML = html;
        }
        
        // 关闭品种详情弹窗
        function closeVarietyDetailModal() {
            document.getElementById('varietyDetailModal').style.display = 'none';
        }
        
        // loading 遮罩
        function showLoadingOverlay(show) {
            let overlay = document.getElementById('loadingOverlay');
            if (!overlay && show) {
                overlay = document.createElement('div');
                overlay.id = 'loadingOverlay';
                overlay.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.6);z-index:9999;display:flex;align-items:center;justify-content:center;';
                overlay.innerHTML = '<div style="background:#1a1a2e;padding:20px 40px;border-radius:8px;color:#00d4ff;font-size:16px;">数据加载中...</div>';
                document.body.appendChild(overlay);
            } else if (overlay && !show) {
                overlay.remove();
            }
        }

        // 页面加载时初始化（在线版：先异步加载默认日期数据）
        (async function() {
            const data = await loadDateData(defaultDate);
            if (data) {
                allData[defaultDate] = data;
            }
            initDateSelector();
        })();
    